- "Navigated the treacherous waters" metaphorically refers to executing equations;
- "Quadratic equations" refers to equation types with the name 'Quadratic';
- "At least once" refers to having at least one execution status of 'success'.

sql:
SELECT user_id, test_case_id
FROM test_case_permissions
WHERE permission_level = 'write';

SELECT equation_type_name, COUNT(*) AS number_of_quadratic_equations
FROM equation_types
WHERE equation_type_name = 'Quadratic';

SELECT execution_id, actual_output
FROM test_case_executions
WHERE execution_status = 'success';
